// ?? vs || comparison
const count = 0;
console.log(count ?? 'default');  // 0     ✅ 0 is valid
console.log(count || 'default');  // 'default' ❌ 0 is falsy!

const name = '';
console.log(name ?? 'Anonymous');  // ''          (empty string is valid)
console.log(name || 'Anonymous');  // 'Anonymous' (empty string is falsy)

// Typical use: API response with defaults
const apiData = { score: 0, label: '' };
const score = apiData.score ?? 'No score';  // 0
const label = apiData.label ?? 'No label';  // ''

// Combined with optional chaining
const user = null;
const city = user?.address?.city ?? 'Unknown';
console.log(city); // 'Unknown'
